// MAXIMUM VALIDATION ENGINE v3 — Fixed dimension mapping
// Store/Rentoilage: dims = Largeur × avancée. Surface = L×A
// Volet/Moustiquaire: dims = Largeur × Hauteur
// Lambrequin: Largeur + Hauteur (tombée)

const items = $input.all();
const results = [];

// ─── Categories that use avancée as 2nd dimension ───
const AVANCEE_CATS = ['Store banne', 'Rentoilage', 'Rentoilage double pente'];
const HAUTEUR_CATS = ['Volet roulant', 'Moustiquaire', 'Lambrequin'];
const SURFACE_CATS = ['Store banne', 'Rentoilage', 'Rentoilage double pente']; // Surface = L×A

// ─── MANDATORY FIELDS BY CATEGORY ───
const MANDATORY = {
  'Store banne': ['Largeur_mm', 'avancée', 'Surface_m2', 'Couleur_toile', 'Couleur_armature', 'Moteur', 'Forme_lambrequin', 'Jonc_haut', 'Jonc_bas'],
  'Lambrequin': ['Largeur_mm', 'Hauteur_mm', 'Couleur_toile', 'Forme_lambrequin'],
  'Rentoilage': ['Largeur_mm', 'avancée', 'Couleur_toile'],
  'Rentoilage double pente': ['Largeur_mm', 'avancée', 'Couleur_toile'],
  'Volet roulant': ['Largeur_mm', 'Hauteur_mm', 'Moteur', 'Couleur_armature'],
  'Moustiquaire': ['Largeur_mm', 'Hauteur_mm', 'Couleur_toile'],
  'Parasol': ['Designation'],
  'Composant': ['Designation']
};

// ─── DIMENSION RANGES BY CATEGORY (mm) ───
const DIM_RANGES = {
  'Store banne':   { lMin: 1500, lMax: 7000, aMin: 1500, aMax: 4500, hMin: 0, hMax: 500 },
  'Lambrequin':    { lMin: 500,  lMax: 15000, hMin: 100, hMax: 1500 },
  'Rentoilage':    { lMin: 1000, lMax: 7000, aMin: 1000, aMax: 4500 },
  'Rentoilage double pente': { lMin: 1000, lMax: 7000, aMin: 1000, aMax: 4500 },
  'Volet roulant': { lMin: 400,  lMax: 4000, hMin: 400,  hMax: 3500 },
  'Moustiquaire':  { lMin: 400,  lMax: 3000, hMin: 400,  hMax: 3000 },
  'Parasol':       {},
  'Composant':     {}
};

// ─── OCR CATEGORY CORRECTIONS ───
const OCR_CAT_FIXES = {
  'store banne': 'Store banne', 'store-banne': 'Store banne', 'storebanne': 'Store banne',
  'store bane': 'Store banne', 'store banné': 'Store banne',
  'lambrequin': 'Lambrequin', 'lamberquin': 'Lambrequin', 'lambroquin': 'Lambrequin',
  'volet roulant': 'Volet roulant', 'volet-roulant': 'Volet roulant',
  'moustiquaire': 'Moustiquaire', 'moustiqaire': 'Moustiquaire',
  'rentoilage': 'Rentoilage', 'rentoillage': 'Rentoilage', 're-toilage': 'Rentoilage',
  'rentoilage double pente': 'Rentoilage double pente',
  'parasol': 'Parasol', 'parrasol': 'Parasol',
  'composant': 'Composant', 'accessoire': 'Composant', 'pièce': 'Composant'
};

const FABRIC_BRANDS = ['dickson', 'orchestra', 'sunworker', 'sattler', 'sunbrella', 'para', 'tempotest', 'recacril', 'docril'];
const MOTOR_BRANDS = ['somfy', 'nice', 'came', 'bubendorff', 'simu', 'becker', 'asa', 'gaposa', 'mottura'];

for (const item of items) {
  const f = item.json.fields || item.json;
  const notes = [];
  const corrections = {};

  // ─── 1. CATEGORY CORRECTION ───
  let cat = (f.Categorie || '').trim();
  const catLower = cat.toLowerCase();
  if (OCR_CAT_FIXES[catLower] && OCR_CAT_FIXES[catLower] !== cat) {
    corrections.Categorie = OCR_CAT_FIXES[catLower];
    cat = OCR_CAT_FIXES[catLower];
    notes.push('Catégorie corrigée → ' + cat);
  }
  if (!MANDATORY[cat]) {
    notes.push('⚠ Catégorie inconnue: "' + cat + '"');
    cat = 'Parasol';
  }

  // ─── 2. DIMENSION SWAP DETECTION ───
  // If AI put the 2nd dimension in wrong field, fix it
  const largeur = Number(f.Largeur_mm) || 0;
  const hauteur = Number(f.Hauteur_mm) || 0;
  const avancee = Number(f.avancée) || Number(f['avancée']) || 0;

  if (AVANCEE_CATS.includes(cat)) {
    // For stores/rentoilages: 2nd dim should be in avancée, NOT Hauteur_mm
    if (hauteur > 500 && avancee === 0) {
      // AI probably put avancée in Hauteur_mm by mistake
      corrections.avancée = hauteur;
      corrections.Hauteur_mm = 0; // Clear wrong value (or leave for lambrequin height)
      notes.push('Dimension corrigée: Hauteur_mm(' + hauteur + ') → avancée (store/rentoilage)');
    }
    // If both hauteur and avancée are set, hauteur should be small (lambrequin height)
    if (hauteur > 500 && avancee > 0) {
      notes.push('⚠ Hauteur_mm=' + hauteur + ' élevée pour ' + cat + ' (devrait être hauteur lambrequin ≤500mm ou vide)');
    }
  }

  if (HAUTEUR_CATS.includes(cat)) {
    // For volets/moustiquaires: 2nd dim should be in Hauteur_mm
    if (avancee > 0 && hauteur === 0) {
      // AI probably put hauteur in avancée by mistake
      corrections.Hauteur_mm = avancee;
      corrections.avancée = 0;
      notes.push('Dimension corrigée: avancée(' + avancee + ') → Hauteur_mm (volet/moustiquaire)');
    }
  }

  // ─── 3. MANDATORY FIELD CHECK ───
  const mandatory = MANDATORY[cat] || MANDATORY['Parasol'];
  const missingFields = [];
  for (const field of mandatory) {
    let val = f[field];
    // Check if a correction fills this field
    if (corrections[field] !== undefined && corrections[field] !== 0) val = corrections[field];
    if (val === undefined || val === null || val === '' || val === 0) {
      missingFields.push(field);
    }
  }

  // ─── 4. DIMENSION SANITY CHECKS ───
  const effLargeur = corrections.Largeur_mm || largeur;
  const effAvancee = corrections.avancée || avancee;
  const effHauteur = corrections.Hauteur_mm !== undefined ? corrections.Hauteur_mm : hauteur;
  const range = DIM_RANGES[cat] || {};

  // Largeur checks
  if (effLargeur > 0 && effLargeur < 100 && cat !== 'Parasol') {
    corrections.Largeur_mm = effLargeur * 10;
    notes.push('Largeur probablement en cm → ' + (effLargeur * 10) + 'mm');
  } else if (effLargeur > 0 && range.lMin && effLargeur < range.lMin) {
    notes.push('⚠ Largeur petite: ' + effLargeur + 'mm (min: ' + range.lMin + ')');
  } else if (effLargeur > 0 && range.lMax && effLargeur > range.lMax) {
    notes.push('⚠ Largeur grande: ' + effLargeur + 'mm (max: ' + range.lMax + ')');
  }

  // Avancée checks (for store/rentoilage)
  if (AVANCEE_CATS.includes(cat) && effAvancee > 0) {
    if (effAvancee < 100) {
      corrections.avancée = effAvancee * 10;
      notes.push('Avancée probablement en cm → ' + (effAvancee * 10) + 'mm');
    } else if (range.aMin && effAvancee < range.aMin) {
      notes.push('⚠ Avancée petite: ' + effAvancee + 'mm (min: ' + range.aMin + ')');
    } else if (range.aMax && effAvancee > range.aMax) {
      notes.push('⚠ Avancée grande: ' + effAvancee + 'mm (max: ' + range.aMax + ')');
    }
    // Avancée should not exceed Largeur for stores
    if (effAvancee > 0 && effLargeur > 0 && effAvancee > effLargeur) {
      notes.push('⚠ Avancée(' + effAvancee + ') > Largeur(' + effLargeur + '), vérifier');
    }
  }

  // Hauteur checks (for volet/moustiquaire)
  if (HAUTEUR_CATS.includes(cat) && effHauteur > 0) {
    if (effHauteur < 100) {
      corrections.Hauteur_mm = effHauteur * 10;
      notes.push('Hauteur probablement en cm → ' + (effHauteur * 10) + 'mm');
    } else if (range.hMin && effHauteur < range.hMin) {
      notes.push('⚠ Hauteur petite: ' + effHauteur + 'mm (min: ' + range.hMin + ')');
    } else if (range.hMax && effHauteur > range.hMax) {
      notes.push('⚠ Hauteur grande: ' + effHauteur + 'mm (max: ' + range.hMax + ')');
    }
  }

  // ─── 5. SURFACE_m2 CALCULATION (L × A for stores, not L × H!) ───
  let surface = Number(f.Surface_m2) || 0;
  const finalLargeur = corrections.Largeur_mm || effLargeur;
  const finalAvancee = corrections.avancée || effAvancee;
  const finalHauteur = corrections.Hauteur_mm !== undefined ? corrections.Hauteur_mm : effHauteur;

  if (SURFACE_CATS.includes(cat)) {
    // Surface = Largeur × avancée
    if (finalLargeur > 0 && finalAvancee > 0) {
      const calc = Math.round((finalLargeur * finalAvancee / 1000000) * 100) / 100;
      if (surface === 0) {
        corrections.Surface_m2 = calc;
        surface = calc;
        notes.push('Surface_m2 calculée (L×A): ' + calc);
        const idx = missingFields.indexOf('Surface_m2');
        if (idx >= 0) missingFields.splice(idx, 1);
      } else if (Math.abs(surface - calc) > 0.5) {
        notes.push('⚠ Surface incohérente: ' + surface + ' vs L×A=' + calc);
      }
    }
  }

  // ─── 6. PRICE VALIDATION ───
  const prixUnitHT = Number(f.Prix_unitaire_HT) || 0;
  const prixTotalTTC = Number(f.Prix_total_TTC) || 0;
  const quantite = Number(f.Quantite) || 1;

  if (prixUnitHT > 0 && prixTotalTTC > 0) {
    const expectedTTC = prixUnitHT * quantite * 1.20;
    if (Math.abs(prixTotalTTC - expectedTTC) / expectedTTC > 0.15) {
      notes.push('⚠ Prix TTC(' + prixTotalTTC + ') ≠ PU×Qté×1.20(' + expectedTTC.toFixed(2) + ')');
    }
  }
  if (prixUnitHT > 50000) notes.push('⚠ Prix unitaire HT très élevé: ' + prixUnitHT);
  if (prixTotalTTC > 0 && prixTotalTTC < 10) notes.push('⚠ Prix total TTC très bas: ' + prixTotalTTC);

  // ─── 7. FORMAT VALIDATION ───
  const couleurArm = (f.Couleur_armature || '').trim();
  const couleurToile = (f.Couleur_toile || '').trim();
  const moteur = (f.Moteur || '').trim();

  if (couleurArm && !couleurArm.toLowerCase().includes('ral') && cat !== 'Parasol' && couleurArm.length > 2) {
    notes.push('Info: Armature sans code RAL: "' + couleurArm + '"');
  }
  if (couleurToile && couleurToile.length > 2) {
    const hasKnownBrand = FABRIC_BRANDS.some(b => couleurToile.toLowerCase().includes(b));
    if (!hasKnownBrand && cat !== 'Moustiquaire' && cat !== 'Volet roulant') {
      notes.push('Info: Toile sans marque connue: "' + couleurToile + '"');
    }
  }
  if (moteur && moteur.length > 2) {
    const hasKnownMotor = MOTOR_BRANDS.some(b => moteur.toLowerCase().includes(b));
    if (!hasKnownMotor) notes.push('Info: Moteur marque non reconnue: "' + moteur + '"');
  }

  // ─── 8. CLEAN N/A VALUES ───
  for (const [key, val] of Object.entries(f)) {
    if (typeof val === 'string' && /^(n\/a|non\s*(spécifié|disponible|précisé)|null|undefined|none)$/i.test(val.trim())) {
      corrections[key] = '';
      notes.push('Nettoyé "' + val + '" → vide pour ' + key);
    }
  }

  // ─── 9. QUANTITE CHECK ───
  if (quantite <= 0) {
    corrections.Quantite = 1;
    notes.push('Quantité corrigée: 0 → 1');
  }

  // ─── 10. COMPUTE CONFIDENCE SCORE ───
  const aiScore = Number(f.confidence_score) || 0;
  const totalMandatory = mandatory.length;
  const foundCount = totalMandatory - missingFields.length;
  const fieldScore = totalMandatory > 0 ? Math.round((foundCount / totalMandatory) * 100) : 100;
  const warningCount = notes.filter(n => n.startsWith('⚠')).length;
  const warningPenalty = Math.min(warningCount * 5, 25);

  let finalScore;
  if (aiScore > 0) {
    finalScore = Math.round((aiScore * 0.4 + fieldScore * 0.4 + (100 - warningPenalty) * 0.2));
  } else {
    finalScore = Math.round(fieldScore * 0.7 + (100 - warningPenalty) * 0.3);
  }
  finalScore = Math.max(0, Math.min(100, finalScore));

  const statutValidation = finalScore >= 85 ? 'En attente' : 'À réviser';

  if (missingFields.length > 0) {
    notes.unshift('Champs manquants: ' + missingFields.join(', '));
  }

  const aiNotes = (f.validation_notes || '').trim();
  const allNotes = aiNotes ? [aiNotes, ...notes] : notes;

  results.push({
    json: {
      ...item.json,
      _validation: {
        confidence_score: finalScore,
        validation_notes: allNotes.join('; ').substring(0, 255),
        statut_validation: statutValidation,
        Surface_m2_calculated: corrections.Surface_m2 || surface || 0,
        category_corrected: corrections.Categorie || cat,
        avancee_corrected: corrections.avancée || 0,
        hauteur_corrected: corrections.Hauteur_mm !== undefined ? corrections.Hauteur_mm : 0,
        largeur_corrected: corrections.Largeur_mm || 0,
        quantite_corrected: corrections.Quantite || 0,
        warning_count: warningCount,
        missing_count: missingFields.length
      }
    }
  });
}

return results;

const BASE_WEBHOOK_URL = 'http://192.168.1.70:5678/webhook';
const items = $input.all();
const results = [];
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const fields = item.json.fields || item.json;
  const recordId = item.json.id;
  const factureNum = fields['Numéro (from Facture_liee)']?.[0] || 'BP';
  const shortId = recordId.replace('rec', '').slice(0, 6).toUpperCase();
  const bonId = factureNum + '-' + shortId;
  const productionUrl = BASE_WEBHOOK_URL + '/production?bon_id=' + encodeURIComponent(bonId);
  const qrCodeUrl = 'https://api.qrserver.com/v1/create-qr-code/?size=300x300&format=png&data=' + encodeURIComponent(productionUrl);
  results.push({ json: { ...item.json, bon_id: bonId, production_url: productionUrl, qr_code_url: qrCodeUrl, record_id: recordId } });
}
return results;

const item = $input.first();
const d = item.json.body || item.json;
$execution.customData.set('pdfUrl', d.pdfUrl || '');
$execution.customData.set('driveFileId', d.driveFileId || '');
$execution.customData.set('factureNum', d.factureNum || '');
$execution.customData.set('pdfId', d.pdfId || '');
return [{ json: { pdfUrl: d.pdfUrl || '', pdfText: d.pdfText || '', pdfId: d.pdfId || '', factureNum: d.factureNum || '', driveFileId: d.driveFileId || '' } }];

const pdfUrl = $execution.customData.get('pdfUrl') || '';
let driveFileId = $execution.customData.get('driveFileId') || '';
if (!driveFileId && pdfUrl) {
  const m = pdfUrl.match(/\/file\/d\/([^/]+)/);
  if (m) driveFileId = m[1];
}
const factureNum = $execution.customData.get('factureNum') || '';
const pdfId = $execution.customData.get('pdfId') || '';
return [{ json: { pdfUrl, driveFileId, factureNum, pdfId } }];

const raw = $json.message?.content || $json.response || '';
// Nettoyer les balises markdown si présentes
let cleaned = raw.trim();
cleaned = cleaned.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/, '').trim();
// Trouver le JSON
const start = cleaned.indexOf('{');
const end = cleaned.lastIndexOf('}');
if (start === -1 || end === -1) {
  return [{ json: { _error: 'No JSON found', raw: raw.substring(0, 500) } }];
}
try {
  const parsed = JSON.parse(cleaned.substring(start, end + 1));
  return [{ json: parsed }];
} catch(e) {
  return [{ json: { _error: e.message, raw: cleaned.substring(0, 500) } }];
}

const facture = $('Insert Facture').first().json;
const parsed = $('Parse Invoice JSON').first().json;
const produits = parsed.produits || [];
if (produits.length === 0) return [{ json: { _no_products: true } }];
return produits.map(p => ({
  json: {
    ...p,
    facture_id: facture.id
  }
}));
